var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드, <color=#ffd34c>제프티 바이오테크</color> 본사\\n<color=#ffd34c>호라이즌</color>, 긴급기동 상태.","JPN":"シャレード、<color=#ffd34c>ジェフティ・バイオテック</color>本社\\n<color=#ffd34c>ホライズン</color>、緊急起動状態。","ENG":"<color=#ffd34c>Jehuty Biotech</color>\xA0HQ building, Charade\\n<color=#ffd34c>Horizon</color> in Emergency Mode","TWN":"查雷德，<color=#ffd34c>傑夫堤生物科技</color> 總公司\\n<color=#ffd34c>地平線</color>，緊急啟動狀態。","SCN":"查雷德，<color=#ffd34c>杰普提生物科技</color>总公司\\n<color=#ffd34c>地平线</color>，紧急启动状态。","DEU":"[[","FRA":"Charade, Quartier général de <color=#ffd34c> Jehuty Biotech </color>\\n<color=#ffd34c>Horizon</color> en mode mesures d'urgence."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>잔여동력 2.3%. 사고회로의 과부하 감지. 재기동이 필요합니다.</color>","JPN":"<color=#ff3636>残余エネルギー2.3％。思考回路の過負荷感知。再起動が必要です。</color>","ENG":"<color=#ff3636>Current remaining power is at 2.3%. Reasoning system overloaded. Reinitialization required.</color>","TWN":"<color=#ff3636>剩餘動能 2.3%。思考迴路超載，需要重新啟動。</color>"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……중요 메시지라고 끄지도 못하게 하는 주제에 징그럽게 울려대는군요.","JPN":"……重要メッセージ扱いでオフにできないとはいえ、ここまでうるさいとうんざりしますね。","ENG":"These system messages are incessantly annoying, especially since I can't turn them off.","TWN":"……一直出現訊息好吵，但因為是重要訊息也關不掉。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"추심을 종결하는 대로 펌웨어 업데이트를 서둘러야겠습니다.","JPN":"取り立てが完了次第、ファームウェアのアップデートを急いで行いましょう。","ENG":"I'd better get my firmware updated as soon as this collection job is over.","TWN":"等討完債後必須盡快更新韌體。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아하하, 뭐야? 진짜 호라이즌이네?","JPN":"アハハ！　なんだ、本当にホライズンじゃん！","ENG":"Haha, what? So it really is Horizon!","TWN":"哈哈哈～什麼嘛～真的是地平線欸！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"난 또~ 갑자기 나타났다길래 비슷하게 입은 가짜인 줄 알았잖아.","JPN":"急に現れたと聞いたから、見た目だけ似てる偽物だと思ったのに～。","ENG":"I thought an imposter dressed like you had shown up when they said you popped out of nowhere.","TWN":"你這樣突～然冒出來，我還以為只是穿著很像的冒牌貨呢～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하마터면 또 얼굴 확인 안 하고 빵야 할 뻔 했어. 에쿵♬","JPN":"また顔の確認もしないでバキューンしちゃうところだったわ、てへっ♬","ENG":"I almost blew a hole right through you without checking your face first! Whoopsie!","TWN":"差點不分三七二十一就砰！先給你一槍了，真是的♬"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……리벳? 당신이 여기 왜 있습니까?","JPN":"……リベット？　あなたがなぜここにいるのですか？","ENG":"…Rivet? What are you doing here?","TWN":"……里維？你怎麼會在這裡？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"정말 좋은 질문이야. 나도 가끔 내가 왜 아직까지 살아 있나 고민하거든.","JPN":"めっちゃいい質問だね。アタシもたまに、なんで自分がまだ生きてるのか考えちゃうの。","ENG":"That's a great question. Sometimes I too wonder why I'm still alive.","TWN":"這個問題問得很好，我有時候也會很煩惱我怎麼還活著？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"역시 즐겁게 살아서 아닐까? 스트레스 안 받는다는 게 장수 비결이라잖아?","JPN":"やっぱり楽しく生きてるからかな？　ストレスを受けないことが長寿の秘訣らしいし！","ENG":"I guess it's all because I'm having a great time? They do say avoiding stress is key to a long and healthy life!","TWN":"是因為我活得很開心嗎？人說不是說長壽的秘訣就是沒有壓力嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"친한 척 말 걸지 말아 주시겠습니까. 굉장히 껄끄럽습니다만.","JPN":"馴れ馴れしくしないでもらえますか。とても気まずいのですが。","ENG":"I wish you'd stop feigning such personal familiarity with me. It is most unsettling.","TWN":"可以請你不要跟我裝熟嗎？我覺得很尷尬。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아잉, 왜 그래. 캄파멘토에서 같이 보냈던 스릴 넘치는 시간을 벌써 잊어 버린 거야?","JPN":"ええーそんなあ。カンパメントで一緒に過ごしたスリリングな時間をもう忘れちゃったの？","ENG":"Aw, come on. Did you already forget about the exhilarating time we spent together in Campamento?","TWN":"哎唷～幹嘛這樣～我們一起在坎帕門托度過的刺激時光，你都忘了嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"기억합니다. 현지 가이드라고 속인 당신이 데몰리션 웜을 자극하는 바람에 한동안 수금을 중단해야 했죠.","JPN":"覚えています。現地ガイドだと騙ったあなたがデモリッションワームを刺激したせいで、しばらく集金を中止せざるを得なくなりました。","ENG":"I remember. I was forced to suspend my collections because you provoked a Demolition Worm after lying to me about being the local guide.","TWN":"我記得。當時你騙我你是地陪，後來還因為你刺激爆破蠕蟲，導致我必須暫時中斷討債行程。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그치? 일상에 짜릿한 활력소까지 불어 넣어 줬는데 엄청 유능한 가이드잖아?","JPN":"でしょ？　平凡な日常に刺激的なシーンを盛り込んであげられる、すごく有能なガイドだと思わない？","ENG":"Exactly! Thanks to me, that trip couldn't have been more exciting! What better guide could you ask for?","TWN":"是不是！我在平凡的日常生活當中，為你增添這麼多趣事，不是很傑出的導遊嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아잉, 그렇게 다짜고짜 쇠파이프부터 휘두르면 어떡해.","JPN":"いやーん、いきなりそんなに鉄パイプを振り回されたらびっくりしちゃうよ～。","ENG":"Aw, you could have at least given me a heads up before you started swinging away.","TWN":"哎唷～怎麼可以不先通知一聲，就用鐵管攻擊人家呢～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"학회의 유일한 정상인을 없앨 셈이야? 너 그렇게 안 봤는데 정말 나쁜 아이구나?","JPN":"学会の唯一の常識人を潰すつもり？　アンタ、意外と悪い子だったのね！","ENG":"Are you trying to get rid of the only sane person in the Society? I didn't take you for such a meanie!","TWN":"你是打算除掉學會唯一的正常人嗎？我不知道原來你真的這麼壞喔？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};